126→/// A vertical audio level meter.
127→struct LevelMeter: View {
128→    let label: String
129→    let level: Float
130→
131→    var body: some View {
132→        VStack(spacing: 4) {
133→            GeometryReader { geometry in
134→                ZStack(alignment: .bottom) {
135→                    RoundedRectangle(cornerRadius: 4)
136→                        .fill(.quaternary)
137→
138→                    RoundedRectangle(cornerRadius: 4)
139→                        .fill(levelColor)
140→                        .frame(
141→                            height: max(
142→                                0,
143→                                geometry.size.height * CGFloat(clampedLevel)
144→                            )
145→                        )
146→                }
147→            }
148→            .frame(width: 24)
149→
150→            Text(label)
151→                .font(.caption2)
152→                .foregroundStyle(.secondary)
153→        }
154→    }
155→
156→    private var clampedLevel: Float {
157→        min(max(level, 0), 1)
158→    }
159→
160→    private var levelColor: Color {
161→        if clampedLevel > 0.8 {
162→            .pabloBlush
163→        } else if clampedLevel > 0.5 {
164→            .pabloHoney
165→        } else {
166→            .pabloSage
167→        }
168→    }
169→}
