172→// MARK: - Pure formatting helpers
173→
174→/// Converts "lastname, firstname" to "Firstname Lastname". Falls back to `.capitalized`.
175→private func formatPatientName(_ raw: String) -> String {
176→    guard raw.contains(", ") else {
177→        return raw.capitalized
178→    }
179→    let parts = raw.components(separatedBy: ", ")
180→    guard parts.count >= 2 else {
181→        return raw.capitalized
182→    }
183→    // parts[0] = last name, parts[1] = first name
184→    let reordered = [parts[1], parts[0]]
185→    return reordered
186→        .map(\.capitalized)
187→        .joined(separator: " ")
188→}
189→
190→/// Parses an ISO 8601 date string and formats it as "MMM d, yyyy".
191→private func formatISODate(_ raw: String?) -> String? {
192→    guard let raw else { return nil }
193→    let iso = ISO8601DateFormatter()
194→    if let date = iso.date(from: raw) {
195→        let df = DateFormatter()
196→        df.dateFormat = "MMM d, yyyy"
197→        return df.string(from: date)
198→    }
199→    // ISO8601DateFormatter requires a time zone designator; try without
200→    let isoNoTZ = ISO8601DateFormatter()
201→    isoNoTZ.formatOptions = [
202→        .withInternetDateTime,
203→        .withDashSeparatorInDate,
204→        .withColonSeparatorInTime,
205→        .withFullDate,
206→    ]
207→    if let date = isoNoTZ.date(from: raw) {
208→        let df = DateFormatter()
209→        df.dateFormat = "MMM d, yyyy"
210→        return df.string(from: date)
211→    }
212→    return raw
213→}
