import SwiftUI

/// Recording controls with record/pause/stop buttons and audio level meters.
struct RecordingControlsView: View {
    let state: RecordingUIState
    let duration: TimeInterval
    let micLevel: Float
    let systemLevel: Float
    let systemAudioActive: Bool

    let onStart: () -> Void
    let onPause: () -> Void
    let onResume: () -> Void
    let onStop: () -> Void

    var body: some View {
        VStack(spacing: 16) {
            Text(formattedDuration)
                .font(.system(size: 48, weight: .light, design: .monospaced))
                .foregroundStyle(state == .recording ? .primary : .secondary)

            Text(stateLabel)
                .font(.pabloBody(11))
                .foregroundStyle(.secondary)
                .textCase(.uppercase)

            HStack(spacing: 24) {
                LevelMeter(label: "Mic", level: micLevel)
                LevelMeter(label: "System", level: systemLevel)
            }
            .frame(height: 100)
            .padding(.vertical, 8)

            systemAudioStatus
            controlButtons
        }
        .padding()
        .background(Color.pabloCream)
    }

    @ViewBuilder
    private var systemAudioStatus: some View {
        if state == .recording || state == .paused {
            StatusIndicator(
                isActive: systemAudioActive,
                activeLabel: "System Audio: Active",
                inactiveLabel: "System Audio: Unavailable"
            )
        }
    }

    private var controlButtons: some View {
        HStack(spacing: 20) {
            switch state {
            case .idle:
                idleButtons
            case .recording:
                recordingButtons
            case .paused:
                pausedButtons
            }
        }
    }

    private var idleButtons: some View {
        Button(action: onStart) {
            Label("Record", systemImage: "record.circle")
                .font(.title2)
        }
        .buttonStyle(.borderedProminent)
        .tint(.pabloHoney)
        .controlSize(.large)
    }

    private var recordingButtons: some View {
        Group {
            Button(action: onPause) {
                Label("Pause", systemImage: "pause.circle")
                    .font(.title2)
            }
            .buttonStyle(.bordered)
            .controlSize(.large)

            stopButton
        }
    }

    private var pausedButtons: some View {
        Group {
            Button(action: onResume) {
                Label("Resume", systemImage: "play.circle")
                    .font(.title2)
            }
            .buttonStyle(.bordered)
            .controlSize(.large)

            stopButton
        }
    }

    private var stopButton: some View {
        Button(action: onStop) {
            Label("Stop", systemImage: "stop.circle")
                .font(.title2)
        }
        .buttonStyle(.borderedProminent)
        .tint(.pabloBrownDeep)
        .controlSize(.large)
    }

    private var formattedDuration: String {
        let minutes = Int(duration) / 60
        let seconds = Int(duration) % 60
        return String(format: "%02d:%02d", minutes, seconds)
    }

    private var stateLabel: String {
        switch state {
        case .idle: "Ready"
        case .recording: "Recording"
        case .paused: "Paused"
        }
    }
}

/// A vertical audio level meter.
struct LevelMeter: View {
    let label: String
    let level: Float

    var body: some View {
        VStack(spacing: 4) {
            GeometryReader { geometry in
                ZStack(alignment: .bottom) {
                    RoundedRectangle(cornerRadius: 4)
                        .fill(.quaternary)

                    RoundedRectangle(cornerRadius: 4)
                        .fill(levelColor)
                        .frame(
                            height: max(
                                0,
                                geometry.size.height * CGFloat(clampedLevel)
                            )
                        )
                }
            }
            .frame(width: 24)

            Text(label)
                .font(.caption2)
                .foregroundStyle(.secondary)
        }
    }

    private var clampedLevel: Float {
        min(max(level, 0), 1)
    }

    private var levelColor: Color {
        if clampedLevel > 0.8 {
            .pabloBlush
        } else if clampedLevel > 0.5 {
            .pabloHoney
        } else {
            .pabloSage
        }
    }
}

#Preview("Idle") {
    RecordingControlsView(
        state: .idle,
        duration: 0,
        micLevel: 0,
        systemLevel: 0,
        systemAudioActive: false,
        onStart: {},
        onPause: {},
        onResume: {},
        onStop: {}
    )
    .frame(width: 400)
}

#Preview("Recording") {
    RecordingControlsView(
        state: .recording,
        duration: 125,
        micLevel: 0.6,
        systemLevel: 0.4,
        systemAudioActive: true,
        onStart: {},
        onPause: {},
        onResume: {},
        onStop: {}
    )
    .frame(width: 400)
}

import SwiftUI

/// Displays a list of past recordings with metadata and upload controls.
struct RecordingListView: View {
    let recordings: [LocalRecording]
    let uploadProgress: [UUID: Double]
    let uploadingIDs: Set<UUID>
    let playingRecordingID: UUID?
    let transcriptionStates: [UUID: TranscriptionState]
    let onUpload: (LocalRecording) -> Void
    let onPlay: (LocalRecording) -> Void
    let onStopPlayback: () -> Void
    let onViewTranscript: (LocalRecording) -> Void
    let onTranscribe: (LocalRecording) -> Void

    var body: some View {
        Group {
            if recordings.isEmpty {
                emptyState
            } else {
                recordingList
            }
        }
    }

    private var emptyState: some View {
        VStack(spacing: 16) {
            Image("PabloBear")
                .resizable()
                .scaledToFit()
                .frame(width: 80, height: 80)
            Text("No recordings yet")
                .font(.pabloDisplay(17))
                .foregroundStyle(Color.pabloBrownDeep)
            Text("Start recording to see your sessions here.")
                .font(.pabloBody(13))
                .foregroundStyle(Color.pabloBrownSoft)
                .multilineTextAlignment(.center)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .padding()
    }

    private var recordingList: some View {
        List(recordings) { recording in
            RecordingRow(
                recording: recording,
                uploadProgress: uploadProgress[recording.id],
                isUploading: uploadingIDs.contains(recording.id),
                isPlaying: playingRecordingID == recording.id,
                transcriptionState: transcriptionStates[recording.id],
                onUpload: { onUpload(recording) },
                onPlay: { onPlay(recording) },
                onStopPlayback: onStopPlayback,
                onViewTranscript: { onViewTranscript(recording) },
                onTranscribe: { onTranscribe(recording) }
            )
            .pabloListRowStyle()
        }
        .pabloListStyle()
    }
}

struct RecordingRow: View {
    let recording: LocalRecording
    let uploadProgress: Double?
    let isUploading: Bool
    let isPlaying: Bool
    let transcriptionState: TranscriptionState?
    let onUpload: () -> Void
    let onPlay: () -> Void
    let onStopPlayback: () -> Void
    let onViewTranscript: () -> Void
    let onTranscribe: () -> Void

    var body: some View {
        HStack {
            Button(action: isPlaying ? onStopPlayback : onPlay) {
                Image(systemName: isPlaying ? "stop.fill" : "play.fill")
                    .frame(width: 24, height: 24)
            }
            .buttonStyle(.borderless)
            .help(isPlaying ? "Stop" : "Play")

            VStack(alignment: .leading, spacing: 4) {
                Text(recording.fileName)
                    .font(.pabloBody(14)).fontWeight(.semibold)
                    .lineLimit(1)

                HStack(spacing: 12) {
                    Label(recording.formattedDuration, systemImage: "clock")
                    Label(recording.formattedDate, systemImage: "calendar")
                    if recording.isEncrypted {
                        Label("Encrypted", systemImage: "lock.fill")
                            .foregroundStyle(Color.pabloSage)
                    }
                }
                .font(.pabloBody(11))
                .foregroundStyle(.secondary)

                transcriptStatusRow
            }

            Spacer()

            uploadStatus
        }
        .padding(.vertical, 4)
    }

    @ViewBuilder
    private var transcriptStatusRow: some View {
        switch transcriptionState {
        case nil:
            if recording.micPCMFileURL != nil {
                Button("Transcribe") { onTranscribe() }
                    .font(.pabloBody(11))
                    .buttonStyle(.borderless)
                    .foregroundStyle(Color.pabloHoney)
            }
        case .running:
            HStack(spacing: 4) {
                ProgressView().controlSize(.mini)
                Text("Transcribing…")
                    .font(.pabloBody(11))
                    .foregroundStyle(.secondary)
            }
        case .awaitingModel:
            HStack(spacing: 4) {
                ProgressView().controlSize(.mini)
                Text("Downloading model…")
                    .font(.pabloBody(11))
                    .foregroundStyle(.secondary)
            }
        case .done, .pendingUpload:
            Button {
                onViewTranscript()
            } label: {
                Label(
                    transcriptionState?.isPendingUpload == true
                        ? "View Transcript (upload pending)" : "View Transcript",
                    systemImage: "doc.text"
                )
                .font(.pabloBody(11))
            }
            .buttonStyle(.borderless)
            .foregroundStyle(Color.pabloHoney)
        case let .failed(message):
            Label(message, systemImage: "exclamationmark.triangle.fill")
                .font(.pabloBody(11))
                .foregroundStyle(Color.pabloHoney)
                .lineLimit(1)
        }
    }

    @ViewBuilder
    private var uploadStatus: some View {
        if recording.isUploaded {
            Label("Uploaded", systemImage: "checkmark.circle.fill")
                .foregroundStyle(Color.pabloSage)
                .font(.caption)
        } else if isUploading {
            VStack(spacing: 2) {
                ProgressView(value: uploadProgress ?? 0)
                    .frame(width: 80)
                Text("\(Int((uploadProgress ?? 0) * 100))%")
                    .font(.caption2)
                    .foregroundStyle(.secondary)
            }
        } else {
            Button("Upload", action: onUpload)
                .buttonStyle(.bordered)
                .controlSize(.small)
        }
    }
}

