  3→/// Browsable, paginated list of all sessions with status filtering.
  4→struct SessionHistoryView: View {
  5→    @Bindable var viewModel: SessionViewModel
  6→    var patients: [Patient] = []
  7→    var pendingUploadCount = 0
  8→    var transcriptionStateForSession: ((String) -> TranscriptionState?)?
  9→    var hasRecordingForSession: ((String) -> Bool)?
 10→    var playingSessionId: String?
 11→    var onRetryUploads: (() -> Void)?
 12→    var onViewTranscript: ((Session) -> Void)?
 13→    var onTranscribeSession: ((Session) -> Void)?
 14→    var onPlaySession: ((Session) -> Void)?
 15→    var onStopPlayback: (() -> Void)?
 16→
 17→    var body: some View {
 18→        VStack(spacing: 0) {
 19→            header
 20→            filterBar
 21→            if pendingUploadCount > 0 {
 22→                pendingUploadBanner
 23→            }
 24→            Divider()
 25→            sessionContent
 26→        }
 27→        .background(Color.pabloCream)
 28→        .task { await viewModel.loadSessions() }
 29→    }
 30→
 31→    // MARK: - Header
 32→
 33→    private var header: some View {
 34→        VStack(alignment: .leading, spacing: 4) {
 35→            Text("Sessions")
 36→                .font(.pabloDisplay(24))
 37→                .foregroundStyle(Color.pabloBrownDeep)
 38→
 39→            Text(subtitleText)
 40→                .font(.pabloBody(13))
 41→                .foregroundStyle(Color.pabloBrownSoft)
 42→        }
 43→        .frame(maxWidth: .infinity, alignment: .leading)
 44→        .padding(.horizontal, 20)
 45→        .padding(.top, 16)
 46→        .padding(.bottom, 8)
 47→    }
 48→
 49→    private var subtitleText: String {
 50→        let total = viewModel.totalSessions
 51→        if total == 0, viewModel.isLoadingSessions {
 52→            return "Loading sessions..."
 53→        }
 54→        if total == 1 {
 55→            return "1 session"
 56→        }
 57→        return "\(total) sessions"
 58→    }
 59→
 60→    // MARK: - Filter bar
 61→
 62→    private var filterBar: some View {
 63→        ScrollView(.horizontal, showsIndicators: false) {
 64→            HStack(spacing: 8) {
 65→                filterCapsule(label: "All", value: nil)
 66→                filterCapsule(label: "Scheduled", value: "scheduled")
 67→                filterCapsule(label: "In Progress", value: "in_progress")
 68→                filterCapsule(label: "Recorded", value: "recording_complete")
 69→                filterCapsule(label: "Complete", value: "finalized")
 70→                filterCapsule(label: "Cancelled", value: "cancelled")
 71→            }
 72→            .padding(.horizontal, 20)
 73→            .padding(.vertical, 8)
 74→        }
 75→    }
 76→
 77→    private func filterCapsule(label: String, value: String?) -> some View {
 78→        let isSelected = viewModel.statusFilter == value
 79→        return Button {
 80→            viewModel.statusFilter = value
 81→        } label: {
 82→            Text(label)
 83→                .font(.pabloBody(12))
 84→                .padding(.horizontal, 12)
 85→                .padding(.vertical, 6)
 86→                .background(
 87→                    isSelected
 88→                        ? filterColor(for: value)
 89→                        : Color.clear
 90→                )
 91→                .foregroundStyle(
 92→                    isSelected
 93→                        ? Color.white
 94→                        : Color.pabloBrownSoft
 95→                )
 96→                .clipShape(Capsule())
 97→                .overlay(
 98→                    Capsule()
 99→                        .stroke(
100→                            isSelected
101→                                ? Color.clear
102→                                : Color.pabloBrownSoft.opacity(0.3),
103→                            lineWidth: 1
104→                        )
105→                )
106→        }
107→        .buttonStyle(.plain)
108→    }
109→
110→    // MARK: - Content
111→
112→    @ViewBuilder
113→    private var sessionContent: some View {
114→        if viewModel.isLoadingSessions, viewModel.sessions.isEmpty {
115→            loadingState
116→        } else if let error = viewModel.errorMessage, viewModel.sessions.isEmpty {
117→            errorState(error)
118→        } else if viewModel.sessions.isEmpty {
119→            emptyState
120→        } else {
121→            sessionList
122→        }
123→    }
124→
125→    private var loadingState: some View {
126→        VStack {
127→            Spacer()
128→            ProgressView("Loading sessions...")
129→                .font(.pabloBody(14))
130→            Spacer()
131→        }
132→        .frame(maxWidth: .infinity)
133→    }
134→
135→    private func errorState(_ message: String) -> some View {
136→        VStack(spacing: 12) {
137→            Spacer()
138→            Image(systemName: "exclamationmark.triangle")
139→                .font(.system(size: 36))
140→                .foregroundStyle(Color.pabloError)
141→            Text("Failed to Load Sessions")
142→                .font(.pabloDisplay(18))
143→                .foregroundStyle(Color.pabloBrownDeep)
144→            Text(message)
145→                .font(.pabloBody(12))
146→                .foregroundStyle(Color.pabloBrownSoft)
147→                .multilineTextAlignment(.center)
148→                .lineLimit(4)
149→                .padding(.horizontal, 40)
150→            Button("Retry") {
151→                Task { await viewModel.loadSessions() }
152→            }
153→            .buttonStyle(.borderedProminent)
154→            .tint(Color.pabloHoney)
155→            Spacer()
156→        }
157→        .frame(maxWidth: .infinity)
158→    }
159→
160→    private var emptyState: some View {
161→        ContentUnavailableView(
162→            "No Sessions",
163→            systemImage: "calendar.badge.exclamationmark",
164→            description: Text(emptyDescription)
165→        )
166→    }
167→
168→    private var emptyDescription: String {
169→        if viewModel.statusFilter != nil {
170→            return "No sessions match the selected filter."
171→        }
172→        return "No sessions found. Sessions will appear here after they are created."
173→    }
174→
175→    private var sessionList: some View {
176→        List {
177→            ForEach(viewModel.sessions, id: \.id) { session in
178→                sessionRow(session)
179→                    .pabloListRowStyle()
180→            }
181→            if viewModel.hasMoreSessions {
182→                loadMoreButton
183→                    .pabloListRowStyle()
184→            }
185→        }
186→        .pabloListStyle()
187→    }
188→
189→    private func sessionRow(_ session: Session) -> some View {
190→        let state = transcriptionStateForSession?(session.id)
191→        let hasRecording = hasRecordingForSession?(session.id) ?? false
192→        let isPlaying = playingSessionId == session.id
193→
194→        return SessionRowView(
195→            session: session,
196→            patientLookup: { id in patients.first { $0.id == id } },
197→            transcriptionState: state,
198→            hasRecording: hasRecording,
199→            isPlaying: isPlaying,
200→            onViewTranscript: state?.transcript != nil
201→                ? { onViewTranscript?(session) } : nil,
202→            onTranscribe: hasRecording
203→                ? { onTranscribeSession?(session) } : nil,
204→            onPlay: hasRecording
205→                ? { onPlaySession?(session) } : nil,
206→            onStopPlayback: isPlaying
207→                ? { onStopPlayback?() } : nil
208→        )
209→    }
210→
211→    private var loadMoreButton: some View {
212→        Button {
213→            Task { await viewModel.loadMoreSessions() }
214→        } label: {
215→            HStack {
216→                Spacer()
217→                if viewModel.isLoadingSessions {
218→                    ProgressView()
219→                        .controlSize(.small)
220→                        .padding(.trailing, 4)
221→                    Text("Loading...")
222→                        .font(.pabloBody(13))
223→                } else {
224→                    Text("Load More")
225→                        .font(.pabloBody(13))
226→                }
227→                Spacer()
228→            }
229→            .foregroundStyle(Color.pabloHoney)
230→            .padding(.vertical, 8)
231→        }
232→        .buttonStyle(.plain)
