        }
        if let id = session.patientId, let patient = patientLookup?(id) {
            let first = patient.firstName.first.map(String.init) ?? ""
            let last = patient.lastName.first.map(String.init) ?? ""
            return "\(first)\(last)".uppercased()
        }
        return "?"
    }

