                        .foregroundStyle(Color.pabloHoney)
                }
                .foregroundStyle(Color.pabloHoney)
            }

            LabeledContent("CPU", value: hardware.isAppleSilicon ? "Apple Silicon" : "Intel")
            LabeledContent("RAM", value: "\(hardware.physicalMemoryGB) GB")

